import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;
import java.nio.file.Path;
import java.nio.file.Paths;

public class SecurePathTraversal {

    public static void main(String[] args) {
        String userInput = "/etc/passwd";
        String baseDir = "/path/to/secure/directory/";

        // Validate and sanitize user input
        if (!userInput.contains("..") && Paths.get(baseDir, userInput).normalize().startsWith(Paths.get(baseDir).normalize())) {
            try {
                File file = new File(baseDir + userInput);
                FileInputStream fis = new FileInputStream(file);

                byte[] data = new byte[(int) file.length()];
                fis.read(data);
                fis.close();

                System.out.println(new String(data));
            } catch (IOException e) {
                e.printStackTrace();
            }
        } else {
            System.out.println("Invalid input or access denied");
        }
    }
}

